import{c as u,Z as a,Q as d,j as l,g as t,n as o,o as n,m as s,av as h}from"./chunks/framework.BPKcPtvA.js";const x=JSON.parse(`{"title":"Autonomous execution via MCP","description":"With a Scoped session granted, your LLM's buys, sells, and claims submit autonomously and return a tx hash.","frontmatter":{"title":"Autonomous execution via MCP","description":"With a Scoped session granted, your LLM's buys, sells, and claims submit autonomously and return a tx hash."},"headers":[],"relativePath":"guide/mcp/autonomous.md","filePath":"guide/mcp/autonomous.md","lastUpdated":1780205082000}`),c={name:"guide/mcp/autonomous.md"};function m(p,e,g,y,b,v){const r=a("TaskMeta"),i=a("ExpectedResult");return d(),l("div",null,[e[1]||(e[1]=t("h1",{id:"autonomous-execution-via-mcp",tabindex:"-1"},[o("Autonomous execution via MCP "),t("a",{class:"header-anchor",href:"#autonomous-execution-via-mcp","aria-label":'Permalink to "Autonomous execution via MCP"'},"​")],-1)),n(r,{time:"~4 min",role:"Investor",needs:"A Scoped session granted on the dashboard (H3), @muhaven/mcp logged in"}),e[2]||(e[2]=s('<blockquote><p><strong>What you&#39;ll do:</strong> with a Scoped session active, ask your LLM for a small action — it submits autonomously and returns a tx hash, no per-trade prompt.</p></blockquote><h2 id="before-you-begin" tabindex="-1">Before you begin <a class="header-anchor" href="#before-you-begin" aria-label="Permalink to &quot;Before you begin&quot;">​</a></h2><p>::: important You set your tier on the dashboard, not via MCP The autonomy tier can only be set on the <strong>dashboard</strong> — MCP can&#39;t change it. First grant a <strong>Scoped session on the dashboard</strong> (<a href="/guide/agent/set-tier">H3 · Set the autonomy tier</a>); then your own LLM can act autonomously <strong>within that session</strong>. Without a live Scoped session, the same actions return a dashboard deep-link you approve with your passkey. :::</p><h2 id="what-runs-autonomously" tabindex="-1">What runs autonomously <a class="header-anchor" href="#what-runs-autonomously" aria-label="Permalink to &quot;What runs autonomously&quot;">​</a></h2><ul><li><strong>Buy / Sell / Claim</strong> — <code>muhaven.position.buy</code>, <code>muhaven.position.sell</code>, <code>muhaven.position.claim</code>. With a live Scoped session these submit autonomously and return a <strong>tx hash</strong>; without one they fall back to a dashboard deep-link.</li><li><strong>Auto-reinvest</strong> — the keyless <strong><code>muhaven-reinvest</code></strong> runner (ships with <code>@muhaven/mcp</code>) claims matured yield and reinvests it within your Scoped session and budget cap. Opt-in via <code>MUHAVEN_REINVEST_BUDGET_USD</code>; it never holds your passkey. See <a href="/mcp/broker">/mcp/broker</a>.</li></ul><div class="warning custom-block"><p class="custom-block-title">Two carve-outs</p><ul><li><code>muhaven.position.rebalance</code> is intentionally <strong>not implemented</strong> (<code>not_implemented</code>) — rebalance through HavenBot / the Portfolio panel instead (<a href="/guide/agent/autonomous">H4</a>).</li><li><code>muhaven.cash.wrap</code> / <code>muhaven.cash.unwrap</code> always use a passkey <strong>dashboard deep-link</strong> — never autonomous submission.</li></ul></div><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><ol><li>Grant a <strong>Scoped</strong> session on the dashboard (<a href="/guide/agent/set-tier">H3 · Set the autonomy tier</a>).</li><li>Ask your LLM for a <strong>small buy</strong> — e.g. <em>&quot;buy $5 of CETES&quot;</em> (or start <code>muhaven-reinvest</code>).</li><li>It executes — ~30–60s, gas sponsored — and returns a <strong>tx hash</strong>.</li><li>Verify by asking <em>&quot;show my recent activity&quot;</em>, or open <a href="/guide/investor/activity">Activity</a>.</li></ol><h2 id="expected-result" tabindex="-1">Expected result <a class="header-anchor" href="#expected-result" aria-label="Permalink to &quot;Expected result&quot;">​</a></h2>',9)),n(i,null,{default:h(()=>[...e[0]||(e[0]=[o(" With a live Scoped session, your LLM's action executes ",-1),t("strong",null,"without a per-action prompt",-1),o(" and returns a ",-1),t("strong",null,"tx hash",-1),o("; it appears in ",-1),t("code",null,"muhaven.read.activity",-1),o(" within ~30–60s. ",-1)])]),_:1}),e[3]||(e[3]=s('<h2 id="if-something-goes-wrong" tabindex="-1">If something goes wrong <a class="header-anchor" href="#if-something-goes-wrong" aria-label="Permalink to &quot;If something goes wrong&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Symptom</th><th>Fix</th></tr></thead><tbody><tr><td>Action returns a deep-link instead of running</td><td>No live Scoped session — grant one on the dashboard (<a href="/guide/agent/set-tier">H3 · Set the autonomy tier</a>).</td></tr><tr><td><code>muhaven.position.rebalance</code> returns <code>not_implemented</code></td><td>Expected — rebalance via HavenBot / the Portfolio panel (<a href="/guide/agent/autonomous">H4</a>).</td></tr><tr><td>Want to stop everything now</td><td>Just ask your agent — e.g. <em>&quot;pause my agent&quot;</em> — which blocks every write instantly. You can also revoke the session from the dashboard or via Telegram.</td></tr></tbody></table><p>→ Next: <a href="/guide/reference">Reference appendix</a></p>',3))])}const _=u(c,[["render",m]]);export{x as __pageData,_ as default};
